VALUES
  ('heelevel3-6f0ba476-moex-00392', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '下列關於危險負擔之敘述，何者正確？', '["因不可歸責於雙方當事人之事由，致一方之給付僅一部不能者，他方免為對待給付之義務", "因不可歸責於雙方當事人之事由，致一方之給付全部不能者，他方免為對待給付之義務；如已 為全部或一部之對待給付者，得依關於無因管理之規定，請求返還", "甲出賣自己之A車於乙，雙方締結買賣契約，約好3日後一手交車一手交錢；孰料，締約隔天 A車被因地震倒塌的圍牆壓毀，由於不可歸責於甲，故甲仍得向乙請求價金", "甲出賣自己之A車於乙，雙方締結買賣契約，約好3日後一手交車一手交錢；孰料，締約隔天 乙試車時不慎撞毀A車，由於可歸責於乙，故甲仍得向乙請求價金 32620、33320"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00393', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '甲所有之A車，出於心中保留，贈與並移轉該車所有權於乙，嗣後乙出賣並移轉該車於第三人丙。 下列敘述，何者錯誤？', '["倘若乙不知甲心中保留，丙為善意且無重大過失之第三人時，丙取得A車之所有權", "倘若乙不知甲心中保留，丙為惡意第三人時，丙取得A車之所有權", "倘若乙明知甲心中保留，丙為善意且無重大過失之第三人時，丙取得A車之所有權", "倘若乙明知甲心中保留，丙為惡意第三人時，丙取得A車之所有權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00394', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '甲向乙購買冰箱，約定分5期清償價金，於價金如期清償完畢時，甲始取得冰箱所有權。在清償 完畢前，該冰箱已由甲占有使用。倘若有第三人丙於條件成就前不慎毀損該冰箱，下列敘述，何 者錯誤？', '["乙得基於所有權人地位向丙主張侵權行為之損害賠償", "甲於條件成就時，得向丙主張損害賠償", "倘若甲對丙毀損冰箱無過失時，則甲仍須支付剩餘價金於乙", "縱使甲將冰箱出賣並移轉所有權於惡意之丁，丁仍取得該冰箱之所有權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00395', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '甲逾越地界，擅自在乙所有之A地上種植蘋果樹，三年後蘋果樹結實纍纍。下列敘述，何者錯誤？', '["蘋果樹之所有權歸乙所有", "蘋果之收取權人為甲", "與蘋果樹分離之蘋果為獨立之物", "蘋果樹為A地之成分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00396', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '甲經營出租冷凍設備，乙在民國（下同）106年3月1日向甲承租設備一套，為期1個月，租金 新臺幣（下同）10萬元，約定租賃期間屆滿時支付之，租賃期間屆滿，乙未支付租金。乙於107 年8月17日自動償還5000元給甲，之後則避不見面。甲乃憤而決定於109年8月16日提起訴 訟，然當日適逢強颱來襲，交通斷絕，全臺公家機關停止辦公3日，甲忙於處理災害事宜，遲至 109年8月19日提起訴訟請求。下列敘述，何者正確？', '["甲對乙之租金請求權，因5年不行使而消滅", "甲對乙之租金請求權之消滅時效，應自106年3月31日起算", "甲對乙之租金請求權之時效，於乙在107年8月17日承認後，因甲在6個月內未起訴，視為 未中斷", "甲對乙之租金請求權之消滅時效因事變而不完成，至109年9月19日始完成之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00397', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '甲向乙借一輛自行車，甲騎乘該自行車時遇見丙，丙甚喜歡該輛自行車，甲事前未經乙同意，即 以甲自己之名義出售該輛自行車於不知情之丙，並移轉該輛自行車所有權於丙。關於買賣之債權 行為與移轉所有權之物權行為，下列敘述，何者正確？', '["債權行為有效，物權行為效力未定", "債權行為效力未定，物權行為有效", "債權行為效力未定，物權行為效力未定", "債權行為及物權行為均有效，但乙得撤銷兩項法律行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00398', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '甲以新臺幣（下同）20萬元向乙購買Ａ錶，乙請求甲先付定金，甲同意，並給付2萬元於乙。下 列敘述，何者正確？', '["2萬元定金為要物契約", "2萬元定金為諾成契約", "2萬元定金為繼續性契約", "契約因不可歸責於雙方當事人之事由，致不能履行時，2萬元定金不得請求返還"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00399', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '下列關於買回之敘述，何者正確？', '["買回之期限不得超過5年，超過5年者，買回之約定無效", "買回之價金，當事人得以特約定之", "買回之費用，原則上由買受人與買回人共同負擔", "買受人因可歸責於自己之事由，致不能交付標的物時，買回之約定失效 32620、33320"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00400', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '甲與乙約定，乙為甲服勞務自110年1月1日起1年，而甲給付報酬。下列敘述，何者錯誤？', '["若甲受領勞務遲延，乙無補服勞務之義務，仍得請求報酬", "甲非經乙同意，不得將其勞務請求權讓與第三人", "乙非經甲同意，不得使第三人代服勞務", "乙得隨時終止契約，但有利於甲之習慣者，從其習慣"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00401', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '下列關於合夥人責任之敘述，何者正確？', '["民法第681條規定，合夥人對於合夥債務，連帶負其責任，故債權人得選擇先向合夥人個人單 獨所有之財產求償。若有不足之額，再向合夥財產求償", "民法第681條，就合夥人就合夥對外所負之責任，採取併存主義", "依民法規定合夥債務，原則上為各合夥人之公同共有債務", "民法第681條所稱之連帶，係指合夥人與合夥財產之連帶關係"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL)
